class Solution:
    def subarraysDivByK(self, nums, k):
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        count = 0
        for i in range(n):
            for j in range(i + 1, n + 1):
                if (prefix[j] - prefix[i]) % k == 0:
                    count += 1
        return count

