var subarraysDivByK = function(nums, k) {
    const seen = new Map();
    seen.set(0, 1);
    let prefix = 0, count = 0;
    for (const x of nums) {
        prefix = ((prefix + x) % k + k) % k;
        const c = seen.get(prefix) || 0;
        count += c;
        seen.set(prefix, c + 1);
    }
    return count;
};
